// Validate Algolia API response
// If the HTTP node failed, item.error will be set (because continueOnFail=true)
const item = $input.item.json;

if (item.error) {
  // Log clearly in n8n execution log and stop
  throw new Error(
    `[API ERROR] Algolia HN API request failed: ${JSON.stringify(item.error)}\n` +
    `ACTION REQUIRED: Check your internet connection. If this persists, the Algolia API may be temporarily down. The pipeline will retry automatically at the next scheduled run (every 6 hours).`
  );
}

const hits = item.hits;
if (!hits || !Array.isArray(hits) || hits.length === 0) {
  throw new Error(
    `[API ERROR] Algolia returned an empty response — no stories found.\n` +
    `This is usually temporary. Pipeline will retry in 6 hours.`
  );
}

return { json: item };

// Deduplication gate — saves Gemini quota by skipping unchanged runs
const hits = $input.item.json.hits || [];
const currentIds = hits.map(h => h.objectID).sort().join(',');

const staticData = $getWorkflowStaticData('global');
const lastIds = staticData.lastTopIds || '';

if (currentIds === lastIds && currentIds !== '') {
  // Stories unchanged — stop cleanly with an informational message (not an error)
  return [];
}

staticData.lastTopIds = currentIds;
return { json: $input.item.json };

const hits = $input.item.json.hits || [];
const sourceUrl = 'https://hn.algolia.com/api/v1/search?tags=front_page';
const rawPayload = JSON.stringify(hits);
return { json: { source_url: sourceUrl, raw_payload: rawPayload } };

// Build readable story list for Gemini — titles + scores, ~600 tokens max
const rawStr = $('Format Raw Data').first().json.raw_payload;
let hits = [];
try { hits = JSON.parse(rawStr); } catch(e) {}

const storyList = hits.slice(0, 10).map((h, i) =>
  `${i+1}. "${h.title}"\n   Score: ${h.points || 0} | Comments: ${h.num_comments || 0} | By: ${h.author || 'unknown'}`
).join('\n\n');

return { json: { cleaned_text: storyList } };

const cleaned = $('Prep Data for Embedding').first().json.cleaned_text || '';
const analysis = $('Analysis (LLM Agent)').first().json.output || '';
const insight = $input.item.json.output || '';
return { json: { cleaned_text: cleaned, analysis_result: analysis, insight_result: insight } };
